143→                    R.anim.activity_slide_in_from_left,
144→                    R.anim.activity_slide_out_to_right
145→                )
146→                addToBackStack(null)
147→            }
148→            replace(R.id.fragment_container, findFragmentByTag(tag) ?: factory(), tag)
149→            commit()
150→        }
151→    }
